```class Solution {
public:
    int distanceTraveled(int mainTank, int additionalTank) {
        int totalFuel = mainTank + additionalTank;
        int distance = 0;
        while (totalFuel > 0) {
            int fuelConsumed = min(5, mainTank);
            mainTank -= fuelConsumed;
            distance += fuelConsumed * 10;
            if (mainTank < 5) {
                mainTank += min(1, additionalTank);
                additionalTank -= min(1, additionalTank);
            }
        }
        return distance;
    }
};```
